import pandas as pd
import ast
from rapidfuzz import fuzz

books = pd.DataFrame(env['data_1'])
reviews = pd.DataFrame(env['data_3'])

# Parse categories
def is_childrens(cat_str):
    try:
        cats = ast.literal_eval(cat_str) if isinstance(cat_str, str) else cat_str
        return "Children's Books" in cats
    except:
        return False

books['is_childrens'] = books['categories'].apply(is_childrens)
childrens_books = books[books['is_childrens']]

# Fuzzy match book_id and purchase_id
def get_book_id_num(book_id):
    return book_id.replace('bookid_', '')

def get_purchase_id_num(purchase_id):
    return purchase_id.replace('purchaseid_', '')

childrens_books['id_num'] = childrens_books['book_id'].apply(get_book_id_num)
reviews['id_num'] = reviews['purchase_id'].apply(get_purchase_id_num)

merged = pd.merge(childrens_books, reviews, on='id_num')
print(merged[['title', 'avg_rating']].to_string(index=False))

